def transform_record(record: Dict[str, Any]) -> Dict[str, Any]:
    """Normalize field values in a record."""
    result = dict(record)
    result["name"] = result.get("name", "").strip().title()
    result["email"] = result.get("email", "").strip().lower()
    if "age" in result:
        try:
            result["age"] = int(result["age"])
        except (ValueError, TypeError):
            result["age"] = None
    return result

from typing import Optional


def validate_record(record: Dict[str, Any]) -> Optional[str]:
    """Validate a transformed record. Returns error message or None if valid."""
    if not record.get("name"):
        return "missing name"
    if not record.get("email") or "@" not in record["email"]:
        return f"invalid email for {record['name']}"
    if record.get("age") is not None and (record["age"] < 0 or record["age"] > 150):
        return f"invalid age for {record['name']}"
    return None

def process_data(raw_records: List[Dict[str, Any]], db: Database) -> int:
    """Process raw records: transform, validate, and load into database."""
    loaded = 0
    for record in raw_records:
        transformed = transform_record(record)
        error = validate_record(transformed)
        if error:
            logger.warning("Skipping record: %s", error)
            continue
        try:
            db.insert("users", transformed)
            loaded += 1
        except Exception as e:
            logger.error("Failed to insert %s: %s", transformed["name"], e)
    return loaded
